1 & 0 & 0 \\
0 & \cos \delta_x & \sin \delta_x \\
0 & -\sin \delta_x & \cos \delta_x
\end{pmatrix}
\begin{pmatrix}
t' \\
0 \\
x'
\end{pmatrix}
=
\begin{pmatrix}
t' \\
\cos \delta_x \, x' \\
-\sin \delta_x \, x'
\end{pmatrix}
\end{equation}

\section*{Step 3: Rotate Between Lifted Frames}
